<?php $d=__DIR__.'/../stats/';if(!is_dir($d))@mkdir($d,0775,true);$ip=$_SERVER['REMOTE_ADDR']??'0';$day=date('d');$ymd=date('Ymd');$s=substr(hash('sha256','GonKirua|'.$ymd),0,32);$id=rtrim(strtr(base64_encode(hash_hmac('sha256',$ip.'|'.$day,$s,true)),'+/','-_'),'=');$f1="$d/id_jour_$day.txt";$f2="$d/visiteurs_jour_$day.txt";$f3="$d/visites_jour_$day.txt";if(!file_exists($f1))file_put_contents($f1,'');if(!file_exists($f2))file_put_contents($f2,'0');if(!file_exists($f3))file_put_contents($f3,'0');$ids=@file_get_contents($f1);if(strpos($ids,$id."\n")===false){file_put_contents($f1,$id."\n",FILE_APPEND);file_put_contents($f2,(int)file_get_contents($f2)+1);}file_put_contents($f3,(int)file_get_contents($f3)+1);if(@filesize($f1)>262144)file_put_contents("$d/id_jour_{$day}_".date('Hi').".txt.gz",gzencode(file_get_contents($f1),1));$fs=glob("$d/id_jour_*.txt.gz");if(count($fs)>320){array_multisort(array_map('filemtime',$fs),SORT_ASC,$fs);while(count($fs)>320)unlink(array_shift($fs));}foreach(glob("$d/*")as$f)if(filemtime($f)<time()-2682000)unlink($f);
